/**
 * Party Lines Service - Matches PeerSpeak v1 API
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  PartyLine,
  QueryPartyLinesOptions,
  PartyLinesResponse,
  CreatePartyLineOptions,
  CreatePartyLineResult,
} from '../types';

/** Party Lines service - direct mapping to PeerSpeak v1 API */
export class PartyLinesService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  /**
   * Query party lines with filtering and pagination
   * No authentication required for read-only access
   */
  async query(options?: QueryPartyLinesOptions): Promise<PartyLinesResponse> {
    const response = await this.http.get<PartyLinesResponse>(
      this.endpoint('/party-lines'),
      {
        isActive: options?.isActive,
        search: options?.search,
        limit: options?.limit,
        offset: options?.offset,
      }
    );
    return response;
  }

  /**
   * Get all party lines (convenience method)
   */
  async getAll(options?: QueryPartyLinesOptions): Promise<PartyLine[]> {
    const response = await this.query(options);
    return response.partyLines;
  }

  /**
   * Get active party lines
   */
  async getActive(options?: Omit<QueryPartyLinesOptions, 'isActive'>): Promise<PartyLine[]> {
    const response = await this.query({ ...options, isActive: true });
    return response.partyLines;
  }

  /**
   * Search party lines by name or description
   */
  async search(searchTerm: string, options?: Omit<QueryPartyLinesOptions, 'search'>): Promise<PartyLine[]> {
    const response = await this.query({ ...options, search: searchTerm });
    return response.partyLines;
  }

  /**
   * Create a new party line
   * Requires API key authentication
   */
  async create(options: CreatePartyLineOptions): Promise<CreatePartyLineResult> {
    const response = await this.http.post<CreatePartyLineResult>(
      this.endpoint('/party-lines'),
      options
    );
    return response;
  }

  /**
   * Get a party line by room code
   */
  async getByRoomCode(roomCode: string): Promise<PartyLine> {
    const response = await this.http.get<PartyLine>(
      this.endpoint(`/party-lines/code/${roomCode}`)
    );
    return response;
  }

  /**
   * Get a party line by ID
   */
  async getById(id: string): Promise<PartyLine> {
    const response = await this.http.get<PartyLine>(
      this.endpoint(`/party-lines/${id}`)
    );
    return response;
  }
}

