/**
 * Registry Service - Public registry features (no auth required)
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  ConferenceRoom,
  DialProfile,
  PaginationParams,
} from '../types';

/** Profile search result */
export interface ProfileSearchResult {
  walletAddress: string;
  displayName: string;
  avatar?: string;
  bio?: string;
}

/** Registry service for public features */
export class RegistryService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  /**
   * List public rooms
   */
  async listPublicRooms(params?: PaginationParams): Promise<ConferenceRoom[]> {
    const response = await this.http.get<ConferenceRoom[]>(
      this.endpoint('/registry/rooms'),
      params ? { limit: params.limit, offset: params.offset } : undefined
    );
    return response;
  }

  /**
   * Get token info
   */
  async getTokenInfo(contractAddress: string): Promise<{
    name: string;
    symbol: string;
    decimals: number;
    totalSupply: string;
  }> {
    const response = await this.http.get<{
      name: string;
      symbol: string;
      decimals: number;
      totalSupply: string;
    }>(
      this.endpoint(`/registry/tokens/${contractAddress}`)
    );
    return response;
  }

  /**
   * Search profiles
   */
  async searchProfiles(options: {
    query: string;
    limit?: number;
  }): Promise<ProfileSearchResult[]> {
    const response = await this.http.get<ProfileSearchResult[]>(
      this.endpoint('/registry/profiles/search'),
      options
    );
    return response;
  }

  /**
   * Get profile by ENS name
   */
  async getProfileByENS(ensName: string): Promise<DialProfile> {
    const response = await this.http.get<DialProfile>(
      this.endpoint(`/registry/ens/${ensName}`)
    );
    return response;
  }
}

