/**
 * Calls Service - Wallet-to-Wallet Calling
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  Call,
  StartCallOptions,
  DeclineCallOptions,
  CallRecording,
  WalletAddress,
  PaginationParams,
} from '../types';

/** Calls service for wallet-to-wallet calling */
export class CallsService extends BaseService {
  private localStream?: MediaStream;
  private remoteStreams: Map<string, MediaStream> = new Map();

  constructor(http: HttpClient) {
    super(http);
  }

  /**
   * Start a call to another wallet address
   */
  async start(options: StartCallOptions): Promise<Call> {
    const response = await this.http.post<Call>(
      this.endpoint('/calls'),
      options
    );
    return response;
  }

  /**
   * Answer an incoming call
   */
  async answer(callId: string): Promise<Call> {
    const response = await this.http.post<Call>(
      this.endpoint(`/calls/${callId}/answer`)
    );
    return response;
  }

  /**
   * Decline an incoming call
   */
  async decline(callId: string, options?: DeclineCallOptions): Promise<void> {
    await this.http.post(
      this.endpoint(`/calls/${callId}/decline`),
      options
    );
  }

  /**
   * End an active call
   */
  async end(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/end`));
  }

  /**
   * Get call by ID
   */
  async get(callId: string): Promise<Call> {
    const response = await this.http.get<Call>(
      this.endpoint(`/calls/${callId}`)
    );
    return response;
  }

  /**
   * Get call history
   */
  async getHistory(params?: PaginationParams & { with?: WalletAddress }): Promise<Call[]> {
    const queryParams = params ? { ...params } : undefined;
    const response = await this.http.get<Call[] | { calls: Call[]; pagination: unknown }>(
      this.endpoint('/calls'),
      queryParams
    );
    // Backend wraps in { calls: [...], pagination: {...} } inside data envelope
    if (!Array.isArray(response) && 'calls' in response) {
      return response.calls;
    }
    return response as Call[];
  }

  /**
   * Mute your microphone
   */
  async mute(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/mute`));
    // Also mute local stream if available
    if (this.localStream) {
      this.localStream.getAudioTracks().forEach(track => {
        track.enabled = false;
      });
    }
  }

  /**
   * Unmute your microphone
   */
  async unmute(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/unmute`));
    // Also unmute local stream if available
    if (this.localStream) {
      this.localStream.getAudioTracks().forEach(track => {
        track.enabled = true;
      });
    }
  }

  /**
   * Toggle mute state
   */
  async toggleMute(callId: string): Promise<void> {
    // Toggle based on current state - implementation depends on server response
    await this.http.post(this.endpoint(`/calls/${callId}/toggle-mute`));
  }

  /**
   * Disable video
   */
  async disableVideo(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/disable-video`));
    if (this.localStream) {
      this.localStream.getVideoTracks().forEach(track => {
        track.enabled = false;
      });
    }
  }

  /**
   * Enable video
   */
  async enableVideo(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/enable-video`));
    if (this.localStream) {
      this.localStream.getVideoTracks().forEach(track => {
        track.enabled = true;
      });
    }
  }

  /**
   * Toggle video state
   */
  async toggleVideo(callId: string): Promise<void> {
    await this.http.post(this.endpoint(`/calls/${callId}/toggle-video`));
  }

  /**
   * Set speaker (earpiece or speaker)
   */
  async setSpeaker(callId: string, enabled: boolean): Promise<void> {
    await this.http.post(
      this.endpoint(`/calls/${callId}/speaker`),
      { enabled }
    );
  }

  /**
   * Get local media stream for a call
   */
  getLocalStream(_callId: string): MediaStream | undefined {
    return this.localStream;
  }

  /**
   * Get remote media stream for a call
   */
  getRemoteStream(callId: string): MediaStream | undefined {
    return this.remoteStreams.get(callId);
  }

  /**
   * Start recording the call
   */
  async startRecording(callId: string): Promise<CallRecording> {
    const response = await this.http.post<CallRecording>(
      this.endpoint(`/calls/${callId}/recording/start`)
    );
    return response;
  }

  /**
   * Stop recording the call
   */
  async stopRecording(callId: string): Promise<CallRecording> {
    const response = await this.http.post<CallRecording>(
      this.endpoint(`/calls/${callId}/recording/stop`)
    );
    return response;
  }

  /**
   * Set custom ringtone
   */
  setRingtone(audioUrl: string): void {
    // Store ringtone URL for use when receiving calls
    // Implementation depends on platform (web vs native)
    if (typeof window !== 'undefined' && typeof Audio !== 'undefined') {
      // Preload audio for web
      const audio = new Audio(audioUrl);
      audio.preload = 'auto';
    }
  }

  /**
   * Internal: Set local stream (called by WebRTC layer)
   * @internal
   */
  _setLocalStream(stream: MediaStream): void {
    this.localStream = stream;
  }

  /**
   * Internal: Set remote stream (called by WebRTC layer)
   * @internal
   */
  _setRemoteStream(callId: string, stream: MediaStream): void {
    this.remoteStreams.set(callId, stream);
  }

  /**
   * Internal: Clear streams when call ends
   * @internal
   */
  _clearStreams(callId: string): void {
    this.remoteStreams.delete(callId);
  }
}

