/**
 * @file conference.ts
 * @description Conference service for multi-party video conferencing rooms.
 * @layer Services
 *
 * Handles REST signaling (source of truth for server state) and optionally
 * delegates real-time media operations to a pluggable IMediaProvider (e.g. HMS).
 *
 * Dual-dispatch pattern: methods like muteAudio() do both the REST call AND
 * the media provider call. REST is authoritative — media errors are logged
 * but don't prevent the REST operation from succeeding.
 *
 * NOTE: This service is for multi-party conference rooms and party lines.
 * 1:1 P2P calls use PeerJS via CallsService — a completely separate system.
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  ConferenceRoom,
  CreateRoomOptions,
  JoinRoomOptions,
  JoinByUrlOptions,
  Participant,
  RoomRecording,
  RoomMessage,
  SendRoomMessageOptions,
  BreakoutRoom,
  CreateBreakoutRoomsOptions,
  Poll,
  CreatePollOptions,
  PollResults,
  VideoQualitySettings,
  LayoutOption,
  SetLayoutOptions,
  RoomStats,
  IMediaProvider,
  MediaProviderConfig,
} from '../types';

/** Conference service for video conferencing */
export class ConferenceService extends BaseService {
  private participantStreams: Map<string, MediaStream> = new Map();
  private _mediaProvider: IMediaProvider | null = null;

  constructor(http: HttpClient) {
    super(http);
  }

  // ── Media Provider ──────────────────────────────────────────────────

  /**
   * Set the active media provider for real-time audio/video.
   * Pass null to detach.
   */
  setMediaProvider(provider: IMediaProvider | null): void {
    this._mediaProvider = provider;
  }

  /** Get the current media provider, or null if none is set */
  get mediaProvider(): IMediaProvider | null {
    return this._mediaProvider;
  }

  /**
   * Connect to the media session for a room.
   * Requires room.mediaToken (returned by the backend join route).
   * This is a separate step from join() so that join() stays isomorphic (REST-only).
   */
  async connectMedia(
    room: ConferenceRoom,
    userName: string,
    config?: MediaProviderConfig,
  ): Promise<void> {
    if (!this._mediaProvider) {
      throw new Error('No media provider set. Call setMediaProvider() first.');
    }
    if (!room.mediaToken) {
      throw new Error('Room has no mediaToken. Backend may not have HMS integration enabled.');
    }
    await this._mediaProvider.connect(
      {
        authToken: room.mediaToken,
        userName,
        roomId: room.hmsRoomId,
      },
      config,
    );
  }

  /**
   * Disconnect from the media session.
   * Safe to call even if no provider is set or not connected.
   */
  async disconnectMedia(): Promise<void> {
    if (!this._mediaProvider) return;
    try {
      await this._mediaProvider.disconnect();
    } catch (err) {
      console.warn('[Dial SDK] Media disconnect error (non-fatal):', err);
    }
  }

  // ── Room Lifecycle ──────────────────────────────────────────────────

  /**
   * Create a conference room
   */
  async create(options: CreateRoomOptions): Promise<ConferenceRoom> {
    const response = await this.http.post<ConferenceRoom>(
      this.endpoint('/conference/rooms'),
      options
    );
    return response;
  }

  /**
   * Join a conference room by ID.
   * Maps backend field names (token, role) to SDK field names (mediaToken, mediaRole).
   */
  async join(options: JoinRoomOptions): Promise<ConferenceRoom> {
    const response = await this.http.post<ConferenceRoom & { token?: string; role?: string }>(
      this.endpoint(`/conference/rooms/${options.roomId}/join`),
      {
        video: options.video,
        audio: options.audio,
        displayName: options.displayName,
      }
    );
    return this.normalizeRoomResponse(response);
  }

  /**
   * Join a conference room by URL.
   * Maps backend field names (token, role) to SDK field names (mediaToken, mediaRole).
   */
  async joinByUrl(options: JoinByUrlOptions): Promise<ConferenceRoom> {
    const response = await this.http.post<ConferenceRoom & { token?: string; role?: string }>(
      this.endpoint('/conference/rooms/join-by-url'),
      options
    );
    return this.normalizeRoomResponse(response);
  }

  /**
   * Normalize backend response fields to SDK ConferenceRoom shape.
   * Backend returns `token` and `role`; SDK uses `mediaToken` and `mediaRole`.
   */
  private normalizeRoomResponse(
    response: ConferenceRoom & { token?: string; role?: string },
  ): ConferenceRoom {
    const { token, role, ...rest } = response;
    return {
      ...rest,
      mediaToken: rest.mediaToken ?? token,
      mediaRole: rest.mediaRole ?? role,
    };
  }

  /**
   * Leave a conference room.
   * Also disconnects from media session if a provider is active.
   */
  async leave(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/leave`));
    this.participantStreams.delete(roomId);
    await this.disconnectMedia();
  }

  /**
   * Get participants in a room
   */
  async getParticipants(roomId: string): Promise<Participant[]> {
    const response = await this.http.get<Participant[]>(
      this.endpoint(`/conference/rooms/${roomId}/participants`)
    );
    return response;
  }

  /**
   * Get participant's media stream
   */
  getParticipantStream(roomId: string, participantId: string): MediaStream | undefined {
    return this.participantStreams.get(`${roomId}:${participantId}`);
  }

  // ── Audio Controls (dual dispatch: REST + media provider) ───────────

  /**
   * Mute your audio
   */
  async muteAudio(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/mute-audio`));
    this._mediaDispatch(() => this._mediaProvider!.setLocalAudioEnabled(false));
  }

  /**
   * Unmute your audio
   */
  async unmuteAudio(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/unmute-audio`));
    this._mediaDispatch(() => this._mediaProvider!.setLocalAudioEnabled(true));
  }

  /**
   * Mute a specific participant (host only)
   */
  async muteParticipant(roomId: string, participantId: string): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/participants/${participantId}/mute`)
    );
  }

  /**
   * Mute all participants (host only)
   */
  async muteAll(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/mute-all`));
  }

  // ── Video Controls (dual dispatch: REST + media provider) ──────────

  /**
   * Disable your video
   */
  async disableVideo(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/disable-video`));
    this._mediaDispatch(() => this._mediaProvider!.setLocalVideoEnabled(false));
  }

  /**
   * Enable your video
   */
  async enableVideo(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/enable-video`));
    this._mediaDispatch(() => this._mediaProvider!.setLocalVideoEnabled(true));
  }

  /**
   * Request participant to enable video
   */
  async requestVideo(roomId: string, participantId: string): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/participants/${participantId}/request-video`)
    );
  }

  // ── Screen Sharing (dual dispatch: REST + media provider) ──────────

  /**
   * Start screen share
   */
  async startScreenShare(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/screen-share/start`));
    this._mediaDispatch(() => this._mediaProvider!.startScreenShare());
  }

  /**
   * Stop screen share
   */
  async stopScreenShare(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/screen-share/stop`));
    this._mediaDispatch(() => this._mediaProvider!.stopScreenShare());
  }

  // ── Recording ───────────────────────────────────────────────────────

  /**
   * Start recording
   */
  async startRecording(roomId: string): Promise<RoomRecording> {
    const response = await this.http.post<RoomRecording>(
      this.endpoint(`/conference/rooms/${roomId}/recording/start`)
    );
    return response;
  }

  /**
   * Stop recording
   */
  async stopRecording(roomId: string): Promise<RoomRecording> {
    const response = await this.http.post<RoomRecording>(
      this.endpoint(`/conference/rooms/${roomId}/recording/stop`)
    );
    return response;
  }

  /**
   * Get recordings for a room
   */
  async getRecordings(roomId: string): Promise<RoomRecording[]> {
    const response = await this.http.get<RoomRecording[]>(
      this.endpoint(`/conference/rooms/${roomId}/recordings`)
    );
    return response;
  }

  // ── In-Room Messaging ───────────────────────────────────────────────

  /**
   * Send message in room
   */
  async sendMessage(roomId: string, options: SendRoomMessageOptions): Promise<RoomMessage> {
    const response = await this.http.post<RoomMessage>(
      this.endpoint(`/conference/rooms/${roomId}/messages`),
      options
    );
    return response;
  }

  // ── Layout ──────────────────────────────────────────────────────────

  /**
   * Set room layout
   */
  async setLayout(roomId: string, layout: LayoutOption, options?: SetLayoutOptions): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/layout`),
      { layout, ...options }
    );
  }

  // ── Room Management ─────────────────────────────────────────────────

  /**
   * End room (host only)
   */
  async end(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/end`));
  }

  /**
   * Remove participant (host only)
   */
  async removeParticipant(roomId: string, participantId: string): Promise<void> {
    await this.http.delete(
      this.endpoint(`/conference/rooms/${roomId}/participants/${participantId}`)
    );
  }

  /**
   * Transfer host role
   */
  async transferHost(roomId: string, newHostParticipantId: string): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/transfer-host`),
      { participantId: newHostParticipantId }
    );
  }

  // ── Breakout Rooms ──────────────────────────────────────────────────

  /**
   * Create breakout rooms
   */
  async createBreakoutRooms(roomId: string, options: CreateBreakoutRoomsOptions): Promise<BreakoutRoom[]> {
    const response = await this.http.post<BreakoutRoom[]>(
      this.endpoint(`/conference/rooms/${roomId}/breakout-rooms`),
      options
    );
    return response;
  }

  /**
   * Move participant to breakout room
   */
  async moveToBreakout(roomId: string, participantId: string, breakoutRoomId: string): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/breakout-rooms/${breakoutRoomId}/move`),
      { participantId }
    );
  }

  /**
   * Close all breakout rooms
   */
  async closeBreakoutRooms(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/breakout-rooms/close`));
  }

  // ── Polls ───────────────────────────────────────────────────────────

  /**
   * Create poll
   */
  async createPoll(roomId: string, options: CreatePollOptions): Promise<Poll> {
    const response = await this.http.post<Poll>(
      this.endpoint(`/conference/rooms/${roomId}/polls`),
      options
    );
    return response;
  }

  /**
   * Vote on poll
   */
  async vote(roomId: string, pollId: string, optionIndex: number): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/polls/${pollId}/vote`),
      { optionIndex }
    );
  }

  /**
   * Get poll results
   */
  async getPollResults(roomId: string, pollId: string): Promise<PollResults> {
    const response = await this.http.get<PollResults>(
      this.endpoint(`/conference/rooms/${roomId}/polls/${pollId}/results`)
    );
    return response;
  }

  // ── Hand Raising ────────────────────────────────────────────────────

  /**
   * Raise hand
   */
  async raiseHand(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/raise-hand`));
  }

  /**
   * Lower hand
   */
  async lowerHand(roomId: string): Promise<void> {
    await this.http.post(this.endpoint(`/conference/rooms/${roomId}/lower-hand`));
  }

  // ── Quality Settings ────────────────────────────────────────────────

  /**
   * Set video quality
   */
  async setVideoQuality(roomId: string, settings: VideoQualitySettings): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/quality`),
      settings
    );
  }

  /**
   * Enable/disable adaptive quality
   */
  async setAdaptiveQuality(roomId: string, enabled: boolean): Promise<void> {
    await this.http.post(
      this.endpoint(`/conference/rooms/${roomId}/adaptive-quality`),
      { enabled }
    );
  }

  // ── Analytics ───────────────────────────────────────────────────────

  /**
   * Get room statistics
   */
  async getStats(roomId: string): Promise<RoomStats> {
    const response = await this.http.get<RoomStats>(
      this.endpoint(`/conference/rooms/${roomId}/stats`)
    );
    return response;
  }

  /**
   * Internal: Set participant stream
   * @internal
   */
  _setParticipantStream(roomId: string, participantId: string, stream: MediaStream): void {
    this.participantStreams.set(`${roomId}:${participantId}`, stream);
  }

  // ── Private helpers ─────────────────────────────────────────────────

  /**
   * Fire-and-forget media provider call.
   * Logs errors but doesn't throw — REST is the source of truth.
   */
  private _mediaDispatch(fn: () => Promise<void>): void {
    if (!this._mediaProvider) return;
    fn().catch((err) => {
      console.warn('[Dial SDK] Media provider error (non-fatal):', err);
    });
  }
}
