/**
 * Voicemail Service
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  Voicemail,
  StartRecordingOptions,
  RecordingSession,
  GetVoicemailsOptions,
  VoicemailGreeting,
  SetGreetingOptions,
  VoicemailNotificationPreferences,
  Transcription,
  WaveformData,
} from '../types';

/** Voicemail service */
export class VoicemailService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  /**
   * Start recording a voicemail
   */
  async startRecording(options: StartRecordingOptions): Promise<RecordingSession> {
    const response = await this.http.post<RecordingSession>(
      this.endpoint('/voicemails/record'),
      options
    );
    return response;
  }

  /**
   * Stop recording a voicemail
   */
  async stopRecording(voicemailId: string): Promise<Voicemail> {
    const response = await this.http.post<Voicemail>(
      this.endpoint(`/voicemails/${voicemailId}/stop`)
    );
    return response;
  }

  /**
   * Record a voicemail (convenience method)
   */
  async record(options: StartRecordingOptions): Promise<RecordingSession> {
    return this.startRecording(options);
  }

  /**
   * Get all voicemails
   */
  async getAll(options?: GetVoicemailsOptions): Promise<Voicemail[]> {
    const response = await this.http.get<Voicemail[]>(
      this.endpoint('/voicemails'),
      {
        unreadOnly: options?.unreadOnly,
        limit: options?.limit,
        offset: options?.offset,
      }
    );
    return response;
  }

  /**
   * Get a specific voicemail
   */
  async get(voicemailId: string): Promise<Voicemail> {
    const response = await this.http.get<Voicemail>(
      this.endpoint(`/voicemails/${voicemailId}`)
    );
    return response;
  }

  /**
   * Mark voicemail as read
   */
  async markAsRead(voicemailId: string): Promise<void> {
    await this.http.post(this.endpoint(`/voicemails/${voicemailId}/read`));
  }

  /**
   * Request transcription for a voicemail
   */
  async transcribe(voicemailId: string): Promise<Transcription> {
    const response = await this.http.post<Transcription>(
      this.endpoint(`/voicemails/${voicemailId}/transcribe`)
    );
    return response;
  }

  /**
   * Delete a voicemail
   */
  async delete(voicemailId: string): Promise<void> {
    await this.http.delete(this.endpoint(`/voicemails/${voicemailId}`));
  }

  /**
   * Archive a voicemail
   */
  async archive(voicemailId: string): Promise<void> {
    await this.http.post(this.endpoint(`/voicemails/${voicemailId}/archive`));
  }

  /**
   * Get archived voicemails
   */
  async getArchived(): Promise<Voicemail[]> {
    const response = await this.http.get<Voicemail[]>(
      this.endpoint('/voicemails/archived')
    );
    return response;
  }

  /**
   * Download voicemail audio
   */
  async download(voicemailId: string): Promise<Blob> {
    const voicemail = await this.get(voicemailId);
    
    // Fetch the audio file
    const response = await fetch(voicemail.audioUrl);
    return response.blob();
  }

  /**
   * Get waveform data for visualization
   */
  async getWaveform(voicemailId: string): Promise<WaveformData> {
    const response = await this.http.get<WaveformData>(
      this.endpoint(`/voicemails/${voicemailId}/waveform`)
    );
    return response;
  }

  /**
   * Set greeting
   */
  async setGreeting(options: SetGreetingOptions): Promise<VoicemailGreeting> {
    const response = await this.http.post<VoicemailGreeting>(
      this.endpoint('/voicemails/greeting'),
      {
        text: options.text,
        voice: options.voice,
        duration: options.duration,
        // Audio file would be uploaded separately
        hasAudioFile: !!options.audioFile,
      }
    );
    return response;
  }

  /**
   * Get current greeting
   */
  async getGreeting(): Promise<VoicemailGreeting> {
    const response = await this.http.get<VoicemailGreeting>(
      this.endpoint('/voicemails/greeting')
    );
    return response;
  }

  /**
   * Enable voicemail
   */
  async enable(): Promise<void> {
    await this.http.post(
      this.endpoint('/voicemails/settings'),
      { enabled: true }
    );
  }

  /**
   * Disable voicemail
   */
  async disable(): Promise<void> {
    await this.http.post(
      this.endpoint('/voicemails/settings'),
      { enabled: false }
    );
  }

  /**
   * Check if voicemail is enabled
   */
  async isEnabled(): Promise<boolean> {
    const response = await this.http.get<{ enabled: boolean }>(
      this.endpoint('/voicemails/settings')
    );
    return response.enabled;
  }

  /**
   * Set notification preferences
   */
  async setNotificationPreferences(preferences: VoicemailNotificationPreferences): Promise<void> {
    await this.http.post(
      this.endpoint('/voicemails/notifications'),
      preferences
    );
  }
}

