/**
 * Environment Detection Utilities
 *
 * The Dial SDK is designed to be isomorphic, meaning it can run in both
 * browser and Node.js environments. However, certain features are only
 * available in specific environments.
 *
 * @module @dial/sdk/utils/environment
 */

/** Environment type */
export type Environment = "browser" | "node" | "unknown";

/**
 * Detect the current runtime environment
 */
export function detectEnvironment(): Environment {
  if (typeof window !== "undefined" && typeof document !== "undefined") {
    return "browser";
  }
  if (typeof process !== "undefined" && process.versions?.node) {
    return "node";
  }
  return "unknown";
}

/** Current environment (cached) */
export const ENVIRONMENT = detectEnvironment();

/** Check if running in browser */
export const IS_BROWSER = ENVIRONMENT === "browser";

/** Check if running in Node.js */
export const IS_NODE = ENVIRONMENT === "node";

/**
 * Features that are only available in browser environment
 *
 * @remarks
 * These features require browser-specific APIs like MediaStream, WebRTC, etc.
 * - Audio/Video streaming (requires MediaStream API)
 * - Screen sharing (requires Screen Capture API)
 * - Local media streams (requires getUserMedia)
 * - Real-time call events via WebSocket
 * - Push notifications (requires Service Workers)
 */
export const BROWSER_ONLY_FEATURES = [
  "calls.getLocalStream",
  "calls.getRemoteStream",
  "conference.getParticipantStream",
  "conference.startScreenShare",
  "voicemail.download", // Uses Blob
  "profile.updateAvatar", // Uses File API
] as const;

/**
 * Features that work in both environments (isomorphic)
 *
 * @remarks
 * These features use only HTTP APIs and work identically in both environments.
 * - All authentication (SIWE/SIWS message verification)
 * - Profile management
 * - Messaging (send, receive, history)
 * - Call management (start, end, mute) - but not media streams
 * - Voicemail management
 * - Conference room management
 * - Party Lines queries
 */
export const ISOMORPHIC_FEATURES = [
  "auth.*",
  "profile.*",
  "messages.*",
  "calls.start",
  "calls.answer",
  "calls.decline",
  "calls.end",
  "calls.mute",
  "calls.unmute",
  "calls.getHistory",
  "voicemail.getAll",
  "voicemail.get",
  "voicemail.markAsRead",
  "voicemail.transcribe",
  "conference.create",
  "conference.join",
  "conference.leave",
  "conference.getParticipants",
  "partyLines.*",
  "registry.*",
] as const;

/**
 * Assert that code is running in browser environment
 * @throws Error if not in browser
 */
export function assertBrowser(feature: string): void {
  if (!IS_BROWSER) {
    throw new Error(
      `[Dial SDK] The feature "${feature}" is only available in browser environments. ` +
        `It requires browser-specific APIs (MediaStream, WebRTC, etc.) that are not available in Node.js.`
    );
  }
}

/**
 * Assert that code is running in Node.js environment
 * @throws Error if not in Node.js
 */
export function assertNode(feature: string): void {
  if (!IS_NODE) {
    throw new Error(
      `[Dial SDK] The feature "${feature}" is only available in Node.js environments.`
    );
  }
}

/**
 * Get a cross-platform fetch implementation
 *
 * @remarks
 * We bind fetch to globalThis to preserve the correct context.
 * Without binding, calling `fetch` later loses its `window` context
 * in browsers, causing "Illegal invocation" errors.
 */
export function getFetch(): typeof fetch {
  if (typeof globalThis.fetch !== "undefined") {
    // Bind fetch to globalThis to preserve context when called later
    return globalThis.fetch.bind(globalThis);
  }

  // In older Node.js versions, fetch might not be available
  throw new Error(
    "[Dial SDK] No fetch implementation found. " +
      "Please use Node.js 18+ or provide a custom fetch implementation."
  );
}

/**
 * Log a warning about browser-only feature usage
 */
export function warnBrowserOnly(feature: string): void {
  if (!IS_BROWSER) {
    console.warn(
      `[Dial SDK] Warning: "${feature}" has limited functionality in non-browser environments.`
    );
  }
}
