/**
 * Dial SDK Error types
 */

/** Base SDK error */
export class DialError extends Error {
  public readonly code: string;
  public readonly statusCode: number | undefined;
  public readonly details: Record<string, unknown> | undefined;

  constructor(
    message: string,
    code: string,
    statusCode?: number,
    details?: Record<string, unknown>
  ) {
    super(message);
    this.name = 'DialError';
    this.code = code;
    this.statusCode = statusCode;
    this.details = details;
    Object.setPrototypeOf(this, DialError.prototype);
  }

  toJSON(): Record<string, unknown> {
    return {
      name: this.name,
      message: this.message,
      code: this.code,
      statusCode: this.statusCode,
      details: this.details,
    };
  }
}

/** Authentication error */
export class AuthError extends DialError {
  constructor(message: string, code?: string, details?: Record<string, unknown>) {
    super(message, code ?? 'AUTH_ERROR', 401, details);
    this.name = 'AuthError';
    Object.setPrototypeOf(this, AuthError.prototype);
  }
}

/** API request error */
export class ApiError extends DialError {
  constructor(
    message: string,
    statusCode: number,
    code?: string,
    details?: Record<string, unknown>
  ) {
    super(message, code ?? 'API_ERROR', statusCode, details);
    this.name = 'ApiError';
    Object.setPrototypeOf(this, ApiError.prototype);
  }

  static fromResponse(status: number, body: unknown): ApiError {
    if (typeof body === 'object' && body !== null) {
      const errorBody = body as Record<string, unknown>;
      return new ApiError(
        String(errorBody['error'] ?? errorBody['message'] ?? 'Unknown API error'),
        status,
        String(errorBody['code'] ?? 'API_ERROR'),
        errorBody['details'] as Record<string, unknown> | undefined
      );
    }
    return new ApiError('Unknown API error', status);
  }
}

/** Network/connection error */
export class NetworkError extends DialError {
  constructor(message: string, details?: Record<string, unknown>) {
    super(message, 'NETWORK_ERROR', undefined, details);
    this.name = 'NetworkError';
    Object.setPrototypeOf(this, NetworkError.prototype);
  }
}

/** Timeout error */
export class TimeoutError extends DialError {
  constructor(message?: string) {
    super(message ?? 'Request timed out', 'TIMEOUT_ERROR', 408);
    this.name = 'TimeoutError';
    Object.setPrototypeOf(this, TimeoutError.prototype);
  }
}

/** Validation error */
export class ValidationError extends DialError {
  public readonly field: string | undefined;

  constructor(message: string, field?: string, details?: Record<string, unknown>) {
    super(message, 'VALIDATION_ERROR', 400, details);
    this.name = 'ValidationError';
    this.field = field;
    Object.setPrototypeOf(this, ValidationError.prototype);
  }
}

/** Rate limit error */
export class RateLimitError extends DialError {
  public readonly retryAfter: number | undefined;

  constructor(message?: string, retryAfter?: number) {
    super(message ?? 'Rate limit exceeded', 'RATE_LIMIT_ERROR', 429);
    this.name = 'RateLimitError';
    this.retryAfter = retryAfter;
    Object.setPrototypeOf(this, RateLimitError.prototype);
  }
}

/** Session expired error */
export class SessionExpiredError extends AuthError {
  constructor() {
    super('Session expired. Please re-authenticate.', 'SESSION_EXPIRED');
    this.name = 'SessionExpiredError';
    Object.setPrototypeOf(this, SessionExpiredError.prototype);
  }
}

/** Not found error */
export class NotFoundError extends DialError {
  constructor(message: string, resourceType?: string) {
    super(message, 'NOT_FOUND', 404, resourceType ? { resourceType } : undefined);
    this.name = 'NotFoundError';
    Object.setPrototypeOf(this, NotFoundError.prototype);
  }
}

/** Permission denied error */
export class PermissionDeniedError extends DialError {
  constructor(message?: string, requiredPermission?: string) {
    super(
      message ?? 'Permission denied',
      'PERMISSION_DENIED',
      403,
      requiredPermission ? { requiredPermission } : undefined
    );
    this.name = 'PermissionDeniedError';
    Object.setPrototypeOf(this, PermissionDeniedError.prototype);
  }
}
