/**
 * Profile Service - Dial Profile Management
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  DialProfile,
  UpdateProfileOptions,
  ProfileStatus,
  StatusInfo,
  SetStatusOptions,
  Contact,
  AddContactOptions,
  UpdateContactOptions,
  ProfilePreferences,
  PrivacySettings,
  NotificationSettings,
  DoNotDisturbOptions,
  WalletAddress,
  PaginationParams,
} from '../types';

/** Profile service for managing Dial profiles */
export class ProfileService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  /**
   * Get the current user's profile
   */
  async get(): Promise<DialProfile> {
    const response = await this.http.get<DialProfile>(
      this.endpoint('/profile')
    );
    return response;
  }

  /**
   * Get profile by wallet address
   */
  async getProfile(options: { walletAddress: WalletAddress }): Promise<DialProfile> {
    const response = await this.http.get<DialProfile>(
      this.endpoint(`/profiles/${options.walletAddress}`)
    );
    return response;
  }

  /**
   * Update the current user's profile
   */
  async update(options: UpdateProfileOptions): Promise<DialProfile> {
    const response = await this.http.patch<DialProfile>(
      this.endpoint('/profile'),
      options
    );
    return response;
  }

  /**
   * Update avatar
   */
  async updateAvatar(_options: { file: File | Blob }): Promise<DialProfile> {
    // In a real implementation, this would upload the file first
    // Then update the profile with the URL
    const response = await this.http.post<DialProfile>(
      this.endpoint('/profile/avatar'),
      { hasAvatar: true }
    );
    return response;
  }

  /**
   * Set status
   */
  async setStatus(status: ProfileStatus, options?: SetStatusOptions): Promise<void> {
    await this.http.post(
      this.endpoint('/profile/status'),
      { status, customMessage: options?.customMessage }
    );
  }

  /**
   * Get current status
   */
  async getStatus(): Promise<StatusInfo> {
    const response = await this.http.get<StatusInfo>(
      this.endpoint('/profile/status')
    );
    return response;
  }

  /**
   * Update preferences
   */
  async updatePreferences(preferences: Partial<ProfilePreferences>): Promise<void> {
    await this.http.patch(
      this.endpoint('/profile/preferences'),
      preferences
    );
  }

  /**
   * Update privacy settings
   */
  async updatePrivacy(privacy: Partial<PrivacySettings>): Promise<void> {
    await this.http.patch(
      this.endpoint('/profile/privacy'),
      privacy
    );
  }

  /**
   * Update notification settings
   */
  async updateNotificationSettings(settings: Partial<NotificationSettings>): Promise<void> {
    await this.http.patch(
      this.endpoint('/profile/notifications'),
      settings
    );
  }

  /**
   * Enable Do Not Disturb
   */
  async enableDoNotDisturb(options?: DoNotDisturbOptions): Promise<void> {
    await this.http.post(
      this.endpoint('/profile/dnd'),
      { enabled: true, ...options }
    );
  }

  /**
   * Disable Do Not Disturb
   */
  async disableDoNotDisturb(): Promise<void> {
    await this.http.post(
      this.endpoint('/profile/dnd'),
      { enabled: false }
    );
  }

  /**
   * Block a user
   */
  async blockUser(walletAddress: WalletAddress): Promise<void> {
    await this.http.post(
      this.endpoint('/profile/blocked'),
      { walletAddress }
    );
  }

  /**
   * Unblock a user
   */
  async unblockUser(walletAddress: WalletAddress): Promise<void> {
    await this.http.delete(
      this.endpoint(`/profile/blocked/${walletAddress}`)
    );
  }

  /**
   * Get blocked users
   */
  async getBlockedUsers(): Promise<WalletAddress[]> {
    const response = await this.http.get<WalletAddress[]>(
      this.endpoint('/profile/blocked')
    );
    return response;
  }

  /**
   * Link ENS name
   */
  async linkENS(options: { ensName: string }): Promise<void> {
    await this.http.post(
      this.endpoint('/profile/verify/ens'),
      options
    );
  }

  /**
   * Verify Twitter
   */
  async verifyTwitter(options: { handle: string }): Promise<void> {
    await this.http.post(
      this.endpoint('/profile/verify/twitter'),
      options
    );
  }

  /**
   * Verify GitHub
   */
  async verifyGithub(options: { username: string }): Promise<void> {
    await this.http.post(
      this.endpoint('/profile/verify/github'),
      options
    );
  }

  /**
   * Add contact
   */
  async addContact(options: AddContactOptions): Promise<Contact> {
    const response = await this.http.post<Contact>(
      this.endpoint('/profile/contacts'),
      options
    );
    return response;
  }

  /**
   * Get contacts
   */
  async getContacts(params?: PaginationParams): Promise<Contact[]> {
    const response = await this.http.get<Contact[]>(
      this.endpoint('/profile/contacts'),
      params ? { ...params } : undefined
    );
    return response;
  }

  /**
   * Update contact
   */
  async updateContact(options: UpdateContactOptions): Promise<Contact> {
    const response = await this.http.patch<Contact>(
      this.endpoint(`/profile/contacts/${options.walletAddress}`),
      options
    );
    return response;
  }

  /**
   * Remove contact
   */
  async removeContact(walletAddress: WalletAddress): Promise<void> {
    await this.http.delete(
      this.endpoint(`/profile/contacts/${walletAddress}`)
    );
  }
}

