/**
 * Chats Service - E2EE DMs and Groups
 *
 * @see specs/04-chats.md for full specification
 * @see specs/04a-chats-architecture.md for provider details
 */

import { BaseService } from './base';
import type { HttpClient } from '../http/client';
import type {
  Message,
  SendMessageOptions,
  Conversation,
  GetConversationOptions,
  GetMessagesOptions,
  CreateThreadOptions,
  Thread,
  Group,
  CreateGroupOptions,
  WalletAddress,
  PaginationParams,
} from '../types';

/** Chat service for E2EE DMs and Groups */
export class ChatService extends BaseService {
  constructor(http: HttpClient) {
    super(http);
  }

  /**
   * Send a message to a wallet address
   */
  async send(options: SendMessageOptions): Promise<Message> {
    // If there's media, we need to handle file upload
    if (options.media?.file) {
      return this.sendWithMedia(options);
    }

    const response = await this.http.post<Message>(
      this.endpoint('/chat/messages'),
      {
        to: options.to,
        content: options.content,
        type: options.type ?? 'text',
        threadId: options.threadId,
        provider: options.provider,
        encrypted: options.encrypted,
        replyTo: options.replyTo,
        mentions: options.mentions,
      }
    );
    return response;
  }

  /**
   * Send message with media attachment
   */
  private async sendWithMedia(options: SendMessageOptions): Promise<Message> {
    // First, upload the media file
    // This would typically use a separate upload endpoint
    // For now, we'll send the metadata and assume the file is handled
    const response = await this.http.post<Message>(
      this.endpoint('/chat/messages'),
      {
        to: options.to,
        content: options.media?.caption ?? options.content,
        type: options.type,
        threadId: options.threadId,
        provider: options.provider,
        encrypted: options.encrypted,
        replyTo: options.replyTo,
        mentions: options.mentions,
        // Media will be uploaded separately in a real implementation
        hasMedia: true,
        mediaDuration: options.media?.duration,
      }
    );
    return response;
  }

  /**
   * Get all threads (DMs and Groups)
   */
  async listThreads(params?: PaginationParams): Promise<Conversation[]> {
    const response = await this.http.get<Conversation[]>(
      this.endpoint('/chat/threads'),
      params ? { ...params } : undefined
    );
    return response;
  }

  /**
   * Get conversation with a specific wallet
   * @deprecated Use listThreads() instead
   */
  async getConversations(params?: PaginationParams): Promise<Conversation[]> {
    return this.listThreads(params);
  }

  /**
   * Get thread with a specific wallet
   */
  async getThread(options: GetConversationOptions): Promise<Conversation> {
    const response = await this.http.get<Conversation>(
      this.endpoint('/chat/threads'),
      {
        with: options.with,
        threadModel: options.threadModel,
        provider: options.provider,
      }
    );
    return response;
  }

  /**
   * Get conversation with a specific wallet
   * @deprecated Use getThread() instead
   */
  async getConversation(options: GetConversationOptions): Promise<Conversation> {
    return this.getThread(options);
  }

  /**
   * Get messages with pagination
   */
  async listMessages(options: GetMessagesOptions): Promise<Message[]> {
    const response = await this.http.get<Message[]>(
      this.endpoint('/chat/messages'),
      {
        with: options.with,
        threadId: options.threadId,
        before: options.before?.toString(),
        after: options.after?.toString(),
        limit: options.limit,
        offset: options.offset,
      }
    );
    return response;
  }

  /**
   * Get messages with pagination
   * @deprecated Use listMessages() instead
   */
  async getMessages(options: GetMessagesOptions): Promise<Message[]> {
    return this.listMessages(options);
  }

  /**
   * Mark a message as read
   */
  async markAsRead(messageId: string): Promise<void> {
    await this.http.post(this.endpoint(`/chat/messages/${messageId}/read`));
  }

  /**
   * Add reaction to a message
   */
  async addReaction(options: { messageId: string; emoji: string }): Promise<void> {
    await this.http.post(
      this.endpoint(`/chat/messages/${options.messageId}/reactions`),
      { emoji: options.emoji }
    );
  }

  /**
   * Remove reaction from a message
   */
  async removeReaction(options: { messageId: string; emoji: string }): Promise<void> {
    await this.http.delete(
      this.endpoint(`/chat/messages/${options.messageId}/reactions/${encodeURIComponent(options.emoji)}`)
    );
  }

  /**
   * Start typing indicator
   */
  async startTyping(options: { threadId: string }): Promise<void> {
    await this.http.post(
      this.endpoint('/chat/typing'),
      { threadId: options.threadId, isTyping: true }
    );
  }

  /**
   * Stop typing indicator
   */
  async stopTyping(options: { threadId: string }): Promise<void> {
    await this.http.post(
      this.endpoint('/chat/typing'),
      { threadId: options.threadId, isTyping: false }
    );
  }

  /**
   * Create a DM thread
   */
  async createDM(options: { otherDialUserId: WalletAddress }): Promise<Thread> {
    const response = await this.http.post<Thread>(
      this.endpoint('/chat/threads'),
      {
        type: 'dm',
        participants: [options.otherDialUserId],
      }
    );
    return response;
  }

  /**
   * Create a topic-based thread
   * @deprecated Use createDM() or createGroup() instead
   */
  async createThread(options: CreateThreadOptions): Promise<Thread> {
    const response = await this.http.post<Thread>(
      this.endpoint('/chat/threads'),
      options
    );
    return response;
  }

  /**
   * Create a managed thread (for platform developers)
   */
  async createManagedThread(options: {
    participants: WalletAddress[];
    topic: string;
    metadata?: Record<string, unknown>;
  }): Promise<Thread> {
    const response = await this.http.post<Thread>(
      this.endpoint('/chat/threads/managed'),
      options
    );
    return response;
  }

  /**
   * List managed threads
   */
  async listManagedThreads(options?: {
    filters?: Record<string, unknown>;
  } & PaginationParams): Promise<Thread[]> {
    const response = await this.http.get<Thread[]>(
      this.endpoint('/chat/threads/managed'),
      options?.filters as Record<string, string | number | boolean>
    );
    return response;
  }

  /**
   * Archive a thread
   */
  async archiveThread(threadId: string): Promise<void> {
    await this.http.post(this.endpoint(`/chat/threads/${threadId}/archive`));
  }

  /**
   * Create a group
   */
  async createGroup(options: CreateGroupOptions): Promise<Group> {
    const response = await this.http.post<Group>(
      this.endpoint('/chat/threads'),
      {
        type: 'group',
        name: options.name,
        participants: options.participants,
        provider: options.provider,
        // Avatar would be uploaded separately
      }
    );
    return response;
  }

  /**
   * Invite users to a group
   */
  async inviteToGroup(options: { groupId: string; addresses: WalletAddress[] }): Promise<void> {
    await this.http.post(
      this.endpoint(`/chat/threads/${options.groupId}/invite`),
      { addresses: options.addresses }
    );
  }

  /**
   * Add member to group
   */
  async addMember(options: { threadId: string; address: WalletAddress }): Promise<void> {
    await this.http.post(
      this.endpoint(`/chat/threads/${options.threadId}/members`),
      { address: options.address }
    );
  }

  /**
   * Add member to group
   * @deprecated Use addMember() instead
   */
  async addGroupMember(options: { groupId: string; address: WalletAddress }): Promise<void> {
    return this.addMember({ threadId: options.groupId, address: options.address });
  }

  /**
   * Remove member from group
   */
  async removeMember(options: { threadId: string; address: WalletAddress }): Promise<void> {
    await this.http.delete(
      this.endpoint(`/chat/threads/${options.threadId}/members/${options.address}`)
    );
  }

  /**
   * Remove member from group
   * @deprecated Use removeMember() instead
   */
  async removeGroupMember(options: { groupId: string; address: WalletAddress }): Promise<void> {
    return this.removeMember({ threadId: options.groupId, address: options.address });
  }

  /**
   * Leave a group
   */
  async leaveGroup(threadId: string): Promise<void> {
    await this.http.post(this.endpoint(`/chat/threads/${threadId}/leave`));
  }

  /**
   * Update group info
   */
  async updateGroup(options: {
    threadId: string;
    name?: string;
    avatar?: File | Blob;
  }): Promise<Group> {
    const response = await this.http.patch<Group>(
      this.endpoint(`/chat/threads/${options.threadId}`),
      { name: options.name }
    );
    return response;
  }

  /**
   * Delete a message
   */
  async delete(messageId: string, options?: { forEveryone?: boolean }): Promise<void> {
    await this.http.delete(
      this.endpoint(`/chat/messages/${messageId}`),
      { headers: options?.forEveryone ? { 'X-Delete-For-Everyone': 'true' } : undefined }
    );
  }

  /**
   * Search messages (local only - server-side search incompatible with E2EE)
   */
  async search(options: {
    query: string;
    threadId?: string;
    limit?: number;
  }): Promise<Message[]> {
    const response = await this.http.get<Message[]>(
      this.endpoint('/chat/messages/search'),
      options
    );
    return response;
  }
}
